from typing import TypedDict, Annotated
from langgraph.graph import StateGraph, END
import operator
from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser
from pydantic import BaseModel

llm = ChatOpenAI(model="claude-sonnet-5", temperature=0)

class SectionScore(BaseModel):
    dimension: str
    score: int       # 1-5
    comment: str

structured_llm = llm.with_structured_output(SectionScore)

class ScoreState(TypedDict):
    document: str
    scores: Annotated[list[SectionScore], operator.add]
    weighted_score: float

def score_clarity(state: ScoreState) -> ScoreState:
    result = structured_llm.invoke(
        f"Score the CLARITY of this document 1-5 (dimension='clarity'): {state['document']}"
    )
    return {"scores": [result]}

def score_accuracy(state: ScoreState) -> ScoreState:
    result = structured_llm.invoke(
        f"Score the ACCURACY of this document 1-5 (dimension='accuracy'): {state['document']}"
    )
    return {"scores": [result]}

def score_completeness(state: ScoreState) -> ScoreState:
    result = structured_llm.invoke(
        f"Score the COMPLETENESS 1-5 (dimension='completeness'): {state['document']}"
    )
    return {"scores": [result]}

def compute_weighted_score(state: ScoreState) -> ScoreState:
    weights = {"clarity": 0.3, "accuracy": 0.5, "completeness": 0.2}
    total = sum(
        s.score * weights.get(s.dimension, 0.33)
        for s in state["scores"]
    )
    return {"weighted_score": round(total, 2)}

graph = StateGraph(ScoreState)
for name, fn in [("score_clarity", score_clarity), ("score_accuracy", score_accuracy),
                 ("score_completeness", score_completeness), ("compute_weighted_score", compute_weighted_score)]:
    graph.add_node(name, fn)

graph.set_entry_point("score_clarity")
for scorer in ["score_clarity", "score_accuracy", "score_completeness"]:
    graph.add_edge(scorer, "compute_weighted_score")
graph.add_edge("compute_weighted_score", END)

scorer_chain = graph.compile()
result = scorer_chain.invoke({"document": "Q3 financial summary...", "scores": [], "weighted_score": 0.0})
print(f"Weighted score: {result['weighted_score']}")
for s in result["scores"]:
    print(f"  {s.dimension}: {s.score}/5 — {s.comment[:50]}")

from typing import TypedDict, Annotated
from langgraph.graph import StateGraph, END
import operator
import pytest

class State(TypedDict):
    value: int
    results: Annotated[list[int], operator.add]

def branch_a(state: State) -> State:
    return {"results": [state["value"] * 2]}

def branch_b(state: State) -> State:
    return {"results": [state["value"] * 3]}

def branch_c(state: State) -> State:
    return {"results": [state["value"] + 10]}

def merge(state: State) -> State:
    return {}  # results already merged by reducer

def test_parallel_branches_all_run():
    graph = StateGraph(State)
    for name, fn in [("branch_a", branch_a), ("branch_b", branch_b),
                     ("branch_c", branch_c), ("merge", merge)]:
        graph.add_node(name, fn)
    graph.set_entry_point("branch_a")
    for b in ["branch_a", "branch_b", "branch_c"]:
        graph.add_edge(b, "merge")
    graph.add_edge("merge", END)
    chain = graph.compile()
    result = chain.invoke({"value": 5, "results": []})
    # All three branches ran: 5*2=10, 5*3=15, 5+10=15
    assert sorted(result["results"]) == [10, 15, 15]
    assert len(result["results"]) == 3

def test_reducer_accumulates():
    # Annotated[list, operator.add] merges lists not replaces
    state: State = {"value": 1, "results": []}
    updates_a = branch_a(state)
    updates_b = branch_b(state)
    merged = operator.add(updates_a["results"], updates_b["results"])
    assert 2 in merged
    assert 3 in merged
